var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"후유, 하마터면 목이 날아갈 뻔했구만.","JPN":"ふう、もう少しで首が飛ぶところだったぜ。","ENG":"Sheesh! Almost got my head chopped off.","TWN":"呼，我的脖子差點就要跟身體分家咧！"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L3_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"좋아, 아가씨! 그대로 고개 숙이고 가만히 있으라구!","JPN":"いいぞ、お嬢ちゃん！　そのまま頭下げてじっとしてな！","ENG":"That's it, little lady! Keep your head down just like that!","TWN":"很好，小妹妹！就繼續低著頭吧！"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"우으……. 아파파……","JPN":"うう……いたた……","ENG":"Oof... Oww...","TWN":"呃……好痛喔……"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"하필 거기서 총에 맞네. 상처 흉지면 안 되는데.","JPN":"よりによってあそこで銃に撃たれるなんて。傷跡残ったらどうするのよ。","ENG":"Just had to get hit right then and there. I hope it doesn't scar...","TWN":"偏偏打中這裡，拜託不要留疤。"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"어휴, 끝도 없이 쏘네. 저래선 가까이 못 가겠어.","JPN":"もう、撃ちすぎ。あれじゃあ近づけないじゃない。","ENG":"Ugh, there’s no end to it. I can't get any closer to him.","TWN":"呼，真的是瘋狂掃射欸，根本沒辦法靠近他。"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"그런데 이 냄새는……. 흐음……?","JPN":"でもこの匂いは……ふーん……？","ENG":"Huh? That smell... Hmm...?","TWN":"不過這個味道……嗯……？"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"이봐, 당신들 민병대라고 했지?","JPN":"ねえ、あんたたち民兵隊なんでしょ？","ENG":"Hey, you guys are the Militia, right?","TWN":"喂，你們是民兵隊對吧？"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MISSILE_RELOAD"},{"id":"L16_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"미안한데 우린 어중이떠중이 카운터들보다 훨씬 살벌한 침식체들이랑 부대끼고 사는 처지야.","JPN":"悪いけど、普段から私たちは役立たずのカウンターたちなんかじゃなくて、それよりずっと殺伐とした侵食体を相手してるの。","ENG":"I'm sorry to break it to you, but we live, breathe, and sleep next to C.O.s that are far more brutal than your average Counters.","TWN":"不好意思，我們可是對付過比半吊子制裁者更兇狠的侵蝕體。"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"지금이라도 무기를 버리고 투항하는 게 어때. 러브 앤 피스, 좋잖아.","JPN":"今からでも武器を捨てて投降したらどう？　ラブ・アンド・ピース、結構じゃない。","ENG":"So do yourselves a favor and drop your weapons and surrender. Love and peace, am I right?","TWN":"你們立刻棄械投降吧，如何？愛與和平不是很好嗎？"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"사양하지……! 러브 앤 피스는 그쪽이나 실컷 찾아!","JPN":"遠慮する……！　ラブ・アンド・ピースはそっちで探したらどうだ！","ENG":"I refuse...! You can go find your love and peace somewhere else!","TWN":"我拒絕……！你自己去愛與和平吧！"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"역시 회장님 안목은 정확하군요. 평범해 보이는 용병 분들도 실력이 상당들 하시네요.","JPN":"やはり会長の目は正しいですね。平凡に見える傭兵の方々も相当な実力をお持ちです。","ENG":"As expected, our president has a good eye. Those ordinary-looking mercenaries seem to be quite skilled.","TWN":"會長的眼光果然沒錯，看似平凡的傭兵，能力也是相當不錯呢。"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L25_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"그러니 이제 저항은 포기하세요. 정면으로 부딪치는 건 그쪽 방식이 아닐 텐데요?","JPN":"ですから、もう抵抗は諦めなさい。正面からぶつかるのはそちらのやり方ではないでしょう？","ENG":"Stop resisting and put down your weapons. I know it's not your style to go in head first, no?","TWN":"放棄抵抗吧，正面衝突應該不是你們的行事風格吧？"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"큭……! 닥쳐!","JPN":"くっ……！　黙れ！","ENG":"Kgh...! Shut up!","TWN":"咳……！閉嘴！"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"당신들이 저지르고 다니는 짓은 불법 행위에 지나지 않아요.","JPN":"あなたたちがしていることは不法行為に過ぎません。","ENG":"What you're doing is definitely against the law.","TWN":"你們的所作所為，無非就是非法行為。"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"설마 감정에만 호소하면 전부 용납된다고 생각하는 건가요?","JPN":"まさか感情に訴えれば全部許されるとでも思っているのですか？","ENG":"Or do you believe that if you appeal to emotion, everything will be forgiven?","TWN":"難道你們以為只要訴諸以情，就能夠將犯行合理化嗎？"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"웃기지 마……!","JPN":"ふざけんな……！","ENG":"Hold your tongue...!","TWN":"開什麼玩笑……！"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L30_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"이사님을 살해한 건만큼은 경찰과 별개로 확실히 조사할 겁니다. 각오하세요.","JPN":"常務を殺した件だけは警察とは別に確実に調査するつもりです。覚悟してください。","ENG":"I'll make sure that we investigate the murder of the executive independently of the police. So prepare yourself.","TWN":"殺害理事一事，我們會另外進行調查，請做好心理準備。"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"나는……!!","JPN":"私は……！！","ENG":"But I...!","TWN":"我……！！"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"그래? 그럼 네 팔에 그 불길은 뭐냐?","JPN":"そうか？　じゃあ、お前のその腕の炎はなんだ？","ENG":"Oh, yeah? Then how do you explain the flames on your arms?","TWN":"是嗎？那你手臂上的火焰又是怎麼回事？"},"stage":{"bg":"SS_MILITIA_08","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"처음 각성한 카운터들은 가끔 자기 힘을 주체 못하기도 하지.","JPN":"初めて覚醒したカウンターは、稀に自分の力を制御できないことがある。","ENG":"Sometimes Counters can't control their own power when they get it for the first time.","TWN":"首次覺醒的制裁者的力量往往會失控。"},"stage":{"bg":"SS_MILITIA_08","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"경력자 말을 믿으라고, 신참 카운터.","JPN":"先輩の言うことを信じろよ、新米カウンターくん。","ENG":"Trust me on this, rookie Counter.","TWN":"相信我這個過來人說的話吧，新人制裁者。"},"stage":{"bg":"SS_MILITIA_08","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"<color=#ff3636>복수를 위해서.</color>","JPN":"<color=#ff3636>復讐のために。</color>","ENG":"<color=#ff3636>For revenge.</color>","TWN":"<color=#ff3636>我要報仇。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"나는 믿는다.","JPN":"私は信じている。","ENG":"I believe...","TWN":"我相信，"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"인간은 언제나 약한 존재다.","JPN":"人間は常に弱い存在だ。","ENG":"Humans are always so weak.","TWN":"人類始終是弱者。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"강소영 경위, 정말 확실해?","JPN":"マエカワ警部補、それは確かなの？","ENG":"Lieutenant Kang, are you certain?","TWN":"姜素英員警，你確定嗎？"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_DOOR_CAR"},{"id":"L48_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그럼요. 알파트릭스 쪽 분이 연락해 주셨거든요.","JPN":"もちろんです。アルファトリックスの方が連絡してくださいました。","ENG":"Absolutely. An Alphatrix member called me directly.","TWN":"當然囉，是阿爾法崔克斯的人親自和我聯絡的。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그렇지 않아도 인근에서 총격전이 벌어졌다는 신고가 접수됐어요. 여기 있는 게 확실해요.","JPN":"ちょうど近くで銃撃戦が発生したという通報が入りました。間違いなくここにいます。","ENG":"Plus, we've already received reports of a gunfight taking place nearby. I'm sure it's here.","TWN":"況且警方也獲報這附近發生槍戰，他們一定就在這裡。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"……민간인의 도움을 받는다는 게 맘에 들진 않지만, 좋아.","JPN":"……民間人に助けられたというのは気に入らないけど、いいでしょう。","ENG":"I don't like how we're getting help from a civilian, but all right.","TWN":"……我不喜歡受到老百姓的幫助，但好吧。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"준비해. 바로 돌입하겠어.","JPN":"準備して。すぐに突入する。","ENG":"Get ready. We're going in.","TWN":"準備攻堅！"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"네? 저희 둘뿐인데요?","JPN":"はい？　私たち二人しかいませんけど？","ENG":"What? But it's just the two of us?","TWN":"蛤？就我們二個嗎？"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L3_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"한 시가 급한 상황이야. 범죄자 체포를 민간인들에게 맡길 수는……!","JPN":"一刻を争う事態よ。犯罪者の逮捕を民間人に任せるわけには……！","ENG":"There's no time to waste! We can't let civilians arrest a cr─!","TWN":"現在情況刻不容緩，難道要找老百姓來抓犯……！"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"경정님, 저거……","JPN":"警視様、あれ……","ENG":"Major, look...","TWN":"警正，你看……"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_CROWD_NOISE_02"},{"id":"L8_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"건물에서…… 폭발이……?","JPN":"建物で……爆発が……？","ENG":"The building... exploded...?","TWN":"建築物……爆炸……？"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"경위, 나 먼저 간다! 구조대에 연락해!","JPN":"警部補、私は先に行く！　救助隊に連絡して！","ENG":"Lieutenant, I'll go in first! Call in the rescue team!","TWN":"姜素英員警，我先進去！你請求消防局支援！"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"경정님?! 기다려요, 경정님!","JPN":"警視様！？　待ってください、警視様！","ENG":"Major?! Major, hold on!","TWN":"警正？！你等等，警正！"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};